var b="url",c="应收款对单调整.html",d="generationDate",e=new Date(1781590700201.35),f="defaultAdaptiveView",g="name",h="",i="size",j="width",k=0,l="height",m="adaptiveViews",n="sketchKeys",o="s0",p="variables",q="OnLoadVariable",r="axhubclickvalue",s="page",t="packageId",u="69ee0f3460634768a4214a358f58e8e1",v="type",w="Axure:Page",x="应收款对单调整",y="notes",z="annotations",A="fn",B="1",C="ownerId",D="eb550affff694d77ba63138b4f5c9c46",E="label",F="(下拉列表)",G="说明",H="<p><span>1.默认提示字“请选择客户”</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.展示全部数据</span></p><p><span>2.数据源：[基础数据系统&gt;&gt;客户资料]的客户</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.支持对&quot;客户名称&quot;的模糊搜索</span></p><p><span>3.右侧含“×”的快捷清除按钮</span></p><p><span>4.选中/清空：直接返回结果</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.针对&quot;客户&quot;列进行检索</span></p>",I="2",J="3e2870b6c3634f7190f38a3378cb5b15",K="<p><span>1.默认未选中，展示全部</span></p><p><span>2.可选项：①已记账 ②未记账</span></p><p><span>3.右侧含“×”的快捷清除按钮</span></p><p><span>4.</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">筛选后，直接返回结果</span></p>",L="3",M="beec9056369846c5a480d120cf7c2571",N="记账",O="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#D9001B;\">校验逻辑</span></p><p><span>1.校验存在勾选，否则Toast提示：请至少勾选一行</span></p><p><span>2.校验勾选行的状态</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;\">均为</span><span>“未记账”，否则Toast提示：已记账单据无法再次记账</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\"><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">通过校验，执行逻辑</span></p><p><span>使用嵌套操作的弹窗框进行</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;\">二次确认</span></p><p><span>对勾选数据行</span><span style=\"text-decoration:underline ;\">按&quot;制单时间&quot;顺序</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;text-decoration:underline ;\">依次</span><span>处理，逻辑如下</span></p><p><span>1.将勾选“应收调整单”数据进行处理</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.记账状态：置为'已记账'</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.记账人、记账时间：取当前操作人和操作时间记录</span></p><p><span>2.将“应收调整单”对应的&quot;关联单据&quot;于[财务管理系统&gt;&gt;应收管理：销售结算单]中的相关数据进行处理</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.对“结算金额”重新赋值</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; a1.</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\">新</span><span>结算金额=</span><span style=\"color:#6D000E;\">原</span><span>结算金额+</span><span style=\"color:#6300BF;\">该调整单</span><span>追加应收-</span><span style=\"color:#6300BF;\">该调整单</span><span>扣除应收</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.对“未收金额”重新赋值，根据下述计算结果赋值</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; b1.</span><span style=\"color:#6D000E;\">原</span><span>未收金额+</span><span style=\"color:#6300BF;\">该调整单</span><span>追加应收-</span><span style=\"color:#6300BF;\">该调整单</span><span>扣除应收 </span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#D9001B;\">≥</span><span> 0 ：</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\">新</span><span>未收金额=</span><span style=\"color:#6D000E;\">原</span><span>未收金额+</span><span style=\"color:#6300BF;\">该调整单</span><span>追加应收-</span><span style=\"color:#6300BF;\">该调整单</span><span>扣除应收</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; b2.</span><span style=\"color:#6D000E;\">原</span><span>未收金额+</span><span style=\"color:#6300BF;\">该调整单</span><span>追加应收-</span><span style=\"color:#6300BF;\">该调整单</span><span>扣除应收 </span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#D9001B;\">&lt;</span><span> 0 ：</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\">新</span><span>未收金额= </span><span style=\"color:#0000FF;\">0 </span><span style=\"color:#333333;\"> (扣除应收若比未收金额还多，那多出的已收部分，会重新冲销其它应收或存入已收余额，见举例说明</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#333333;\">4.b </span><span style=\"color:#333333;\">中描述)</span></p><p><span>3.在[财务管理系统&gt;&gt;应收管理：往来记账]中对应生成数据</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.客户：取“应收调整单”对应的&quot;客户&quot;</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.关联单据：取“应收调整单”对应的&quot;应收调整单号&quot;</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; c.销售应收：按'0'传入</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; d.调整追加应收：取“应收调整单”对应的&quot;追加应收&quot;</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; e.调整扣除应收：取“应收调整单”对应的&quot;扣除应收&quot;</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; f.收款金额：按'0'传入</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; g.余额冲销：按'0'传入</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; h.末期应收</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; h1.</span><span style=\"color:#008080;\">客户上期</span><span>末期应收+</span><span style=\"color:#6300BF;\">该调整单</span><span>追加应收-</span><span style=\"color:#6300BF;\">该调整单</span><span>扣除应收 </span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#D9001B;\">≥</span><span> 0 ：</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\">新</span><span>末期应收=</span><span style=\"color:#008080;\">客户上期</span><span>末期应收+</span><span style=\"color:#6300BF;\">该调整单</span><span>追加应收-</span><span style=\"color:#6300BF;\">该调整单</span><span>扣除应收</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; h2.</span><span style=\"color:#008080;\">客户上期</span><span>末期应收+</span><span style=\"color:#6300BF;\">该调整单</span><span>追加应收-</span><span style=\"color:#6300BF;\">该调整单</span><span>扣除应收 </span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#D9001B;\">&lt;</span><span> 0 ：</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\">新</span><span>末期应收=0</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; i.末期余额</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; i1.</span><span style=\"color:#008080;\">客户上期</span><span>末期应收+</span><span style=\"color:#6300BF;\">该调整单</span><span>追加应收-</span><span style=\"color:#6300BF;\">该调整单</span><span>扣除应收 </span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#D9001B;\">≥</span><span> 0 ：</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\">新</span><span>末期余额=</span><span style=\"color:#008080;\">客户上期</span><span>末期余额</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; i2.</span><span style=\"color:#008080;\">客户上期</span><span>末期应收+</span><span style=\"color:#6300BF;\">该调整单</span><span>追加应收-</span><span style=\"color:#6300BF;\">该调整单</span><span>扣除应收 </span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#D9001B;\">&lt;</span><span> 0 ：</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\">新</span><span>末期余额=</span><span style=\"color:#008080;\">客户上期</span><span>末期余额+</span><span style=\"color:#D9001B;\">( </span><span style=\"color:#6300BF;\">该调整单</span><span>扣除应收-</span><span style=\"color:#008080;\">客户上期</span><span>末期应收-</span><span style=\"color:#6300BF;\">该调整单</span><span>追加应收 </span><span style=\"color:#D9001B;\">)</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; j.操作人、操作时间：取当前操作人和操作时间记录</span></p><p><span>4.关闭当前确认弹窗</span></p><p><span>5.返回Toast提示：操作成功</span></p><p><span style=\"color:#333333;\"><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#F59A23;\">→举例说明</span></p><p><span style=\"color:#333333;\">1.若客户于[往来记账]中上期的“末期应收”为'60'，“末期余额”为'0'</span></p><p><span style=\"color:#333333;\">2.该客户的某个结算单的“结算金额”为'700'，进行记账后</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.订单的</span><span style=\"color:#C280FF;\">结算金额</span><span style=\"color:#333333;\">=700</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.订单的</span><span style=\"color:#C280FF;\">未收金额</span><span style=\"color:#333333;\">=700</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; c.本次新增往来记账的</span><span style=\"color:#02830F;\">末期应收</span><span style=\"color:#333333;\">=60+700=760</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; d.本次新增往来记账的</span><span style=\"color:#02830F;\">末期余额</span><span style=\"color:#333333;\">=0</span></p><p><span style=\"color:#333333;\">3.由[财务管理系统&gt;&gt;应收管理：收款单与冲账]针对该结算单支付300并记账后</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.订单的</span><span style=\"color:#C280FF;\">结算金额</span><span style=\"color:#333333;\">=700</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.订单的</span><span style=\"color:#C280FF;\">未收金额</span><span style=\"color:#333333;\">=700-300=400</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; c.本次新增往来记账的</span><span style=\"color:#02830F;\">末期应收</span><span style=\"color:#333333;\">=760-300=460</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; d.本次新增往来记账的</span><span style=\"color:#02830F;\">末期余额</span><span style=\"color:#333333;\">=0</span></p><p><span style=\"color:#333333;\">4.在当前[应收款对单调整]中针对该结算单进行应收的追加和扣除的差异如下</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.若&quot;追加应收&quot;金额为'500'</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; a1.订单的</span><span style=\"color:#C280FF;\">结算金额</span><span style=\"color:#333333;\">=700+500=1200</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; a2.订单的</span><span style=\"color:#C280FF;\">未收金额</span><span style=\"color:#333333;\">=400+500=900</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; a3.本次新增往来记账的</span><span style=\"color:#02830F;\">末期应收</span><span style=\"color:#333333;\">=460+500=960</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; a4.本次新增往来记账的</span><span style=\"color:#02830F;\">末期余额</span><span style=\"color:#333333;\">=0</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.若&quot;扣除应收&quot;金额为'500'</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; b1.订单的</span><span style=\"color:#C280FF;\">结算金额</span><span style=\"color:#333333;\">=700-500=200</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; b2.订单的</span><span style=\"color:#C280FF;\">未收金额</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; b2_1.由于 </span><span style=\"color:#333333;\">400 &lt; 500，即400-500=-100</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; b2_2.则</span><span style=\"color:#C280FF;\">未收金额</span><span style=\"color:#333333;\">=0，那'100'已经多付过的金额将在记账中</span><span style=\"text-decoration:underline ;color:#333333;\">冲销其它应付</span><span style=\"color:#333333;\">或</span><span style=\"text-decoration:underline ;color:#333333;\">存入余额</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; b3.本次新增往来记账的</span><span style=\"color:#02830F;\">末期应收</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; b3_1.由于 </span><span style=\"color:#333333;\">460 &lt; 500，即460-500=-40</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; b3_2.则</span><span style=\"color:#02830F;\">末期应收</span><span style=\"color:#333333;\">=0，即还有'40'已经多付过的金额将存入余额</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; b4.本次新增往来记账的</span><span style=\"color:#02830F;\">末期余额</span><span style=\"color:#333333;\">=0+40=40</span></p>",P="4",Q="c3037cb0a9104ec7a994d873cf7861ce",R="删除",S="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#D9001B;\">校验逻辑</span></p><p><span>1.校验存在勾选，否则Toast提示：请至少勾选一行</span></p><p><span>2.校验勾选行的“制单人”为</span><span style=\"text-decoration:underline ;\">当前账户</span><span>，否则Toast提示：仅可对自己创建的单据进行删除</span></p><p><span>3.校验勾选行的状态</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;\">均为</span><span>“未记账”，否则Toast提示：已记账单据无法删除</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\"><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">通过校验，执行逻辑</span></p><p><span>1使用嵌套操作的弹窗框进行</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;\">二次确认</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.删除勾选单据</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.关闭当前确认弹窗</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; c.返回Toast提示：操作成功</span></p>",T="5",U="8d0ad58808b04bb297e01d988e261572",V="应收调整单",W="<p><span>根据“记账状态”打开对应{弹窗}</span></p>",X="6",Y="03b4fa7d4b104cd39b4570ccaeb17214",Z="* 客户：",ba="<p><span>1.数据源：[基础数据系统&gt;&gt;客户资料]的客户</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.支持对&quot;客户名称&quot;的模糊搜索</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; b.选中后仅返回&quot;客户名称&quot;至当前下拉域</span></p><p><span>2.切换“客户”选项后</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.将“关联单据”内的选项清空，须重新手动选择</span></p>",bb="7",bc="ed72da04fc7d4259a1f0e2870771321d",bd="* 关联单据：",be="<p><span style=\"color:#191717;\">1.数据源：选中“客户”在</span><span>[财务管理系统&gt;&gt;应收管理：销售结算单]</span><span style=\"color:#191717;\">中&quot;记账状态==已记账&quot;的“</span><span>销售结算单</span><span style=\"color:#191717;\">”</span></p><p><span style=\"color:#191717;\">2.每切换“客户”时，当前选项自动清空</span></p>",bf="8",bg="6ef47d304aae495fa877515421cb4be9",bh="结算应收：",bi="<p><span>跟随选中“关联单据”在[财务管理系统&gt;&gt;应收管理：销售结算单]中对应的“结算金额”</span></p>",bj="9",bk="c2405d4e204542dd8fdb1da58f91131c",bl="调整类型：",bm="<p><span>默认值：追加应收</span></p>",bn="10",bo="dbdc4a2ca41e427ebe1413033e36fa78",bp="* 调整金额：",bq="<p><span>1.默认为空</span></p><p><span>2.编辑域：正数，结果保留两位小数</span></p><p><span>3.前端限制：调整金额的值不能超出“结算应收”</span></p>",br="11",bs="3887c080625c4925a3958d947fc4ab96",bt="保存",bu="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#D9001B;\">校验逻辑</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">1.校验“客户”非空，否则Toast提示：请选择客户</span></p><p><span>2.校验当前的“关联单据”是否同时存在&quot;记账状态==未记账&quot;的调整单</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; a.不存在：通过本次校验</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; b.存在：结束全部校验，并</span><span>Toast提示：关联单据存在未记账的单据</span></p><p><span>3.</span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">校验“</span><span>调整金额 &gt; 0</span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">”</span><span>，否则Toast提示：调整金额须大于0</span></p><p><span>4.</span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">校验“</span><span>调整金额 ≤ 结算应收</span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">”</span><span>，否则Toast提示：调整金额不能超出结算应收</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">5.校验“</span><span>调整备注</span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">”非空，否则Toast提示：</span><span>请填写调整备注</span></p><p><span><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">通过校验，执行逻辑</span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\">→新增</span></p><p><span>1.在[财务管理系统&gt;&gt;应收管理：应收款对单调整]内生成一条记录</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.应收调整单：'YSTZ'+'2位年份'+'2位月份'+'3位流水'</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.记账状态：</span><span style=\"color:#D9001B;\">未记账</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; c.客户、关联单据、调整备注：以同名字段赋值</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; d.追加应收：跟随选中的“调整类型”进行赋值<br>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; d1.调整类型==追加应收：取&quot;调整金额&quot;</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; d2.调整类型==扣除应收：视为'0'</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; e.扣除应收：跟随选中的“调整类型”进行赋值<br>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; e1.调整类型==追加应收：视为'0'</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; e2.调整类型==扣除应收：取&quot;调整金额&quot;</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; f.制单人、制单时间、更新人、更新时间：取当前操作人和操作时间记录</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">2.关闭当前弹窗</span></p><p><span>3.Toast提示：操作成功</span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\">→未记账</span></p><p><span>1.更新当前“应收款调整单”相关信息</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.客户、关联单据、调整备注、追加应收、扣除应收：以同名字段更新赋值</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.更新人、更新时间：取当前操作人和操作时间记录</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">2.关闭当前弹窗</span></p><p><span>3.Toast提示：操作成功</span></p>",bv="style",bw="baseStyle",bx="627587b6038d43cca051c114ac41ad32",by="pageAlignment",bz="center",bA="fill",bB="fillType",bC="solid",bD="color",bE=0xFFFFFFFF,bF="image",bG="imageAlignment",bH="near",bI="imageRepeat",bJ="auto",bK="favicon",bL="sketchFactor",bM="0",bN="colorStyle",bO="appliedColor",bP="fontName",bQ="Applied Font",bR="borderWidth",bS="borderVisibility",bT="borderFill",bU=0xFF797979,bV="cornerRadius",bW="cornerVisibility",bX="outerShadow",bY="on",bZ=false,ca="offsetX",cb=5,cc="offsetY",cd="blurRadius",ce="spread",cf="r",cg=0,ch="g",ci="b",cj="a",ck=0.349019607843137,cl="adaptiveStyles",cm="interactionMap",cn="diagram",co="objects",cp="id",cq="8f171d0da5534ae8bd0e9530966dfae8",cr="friendlyType",cs="标题-1420",ct="referenceDiagramObject",cu="styleType",cv="visible",cw=true,cx=1420,cy=800,cz="imageOverrides",cA="masterId",cB="55e23feaedaa46eaa84848efc29f0f2a",cC="89b5facaa193468784aa8c4b8a59bd1b",cD="表格",cE="table",cF=1380,cG=200,cH="location",cI="x",cJ=20,cK="y",cL=121,cM="104377aca14643bdb86846db364cce96",cN="单元格",cO="tableCell",cP="fontWeight",cQ="700",cR="foreGroundFill",cS=0xFF3399